	private void SelectVector(CivAirstrikeVector vector)
	{
		_vector = vector;
		((BaseButton)NorthBtn).Pressed = false;
		((BaseButton)SouthBtn).Pressed = false;
		((BaseButton)EastBtn).Pressed = false;
		((BaseButton)WestBtn).Pressed = false;
		switch (vector)
		{
		case CivAirstrikeVector.North:
			((BaseButton)NorthBtn).Pressed = true;
			break;
		case CivAirstrikeVector.South:
			((BaseButton)SouthBtn).Pressed = true;
			break;
		case CivAirstrikeVector.East:
			((BaseButton)EastBtn).Pressed = true;
			break;
		case CivAirstrikeVector.West:
			((BaseButton)WestBtn).Pressed = true;
			break;
		}
		ClearStatus();
		ScheduleEta();
	}

	private void SelectMode(CivFireSupportMode mode)
	{
		_mode = mode;
		((BaseButton)AviaBtn).Pressed = mode == CivFireSupportMode.Airstrike;
		((BaseButton)ArtBtn).Pressed = mode == CivFireSupportMode.Artillery;
		((BaseButton)SmokeBtn).Pressed = mode == CivFireSupportMode.SmokeScreen;
		((BaseButton)MissileBtn).Pressed = mode == CivFireSupportMode.BallisticMissile;
		((BaseButton)ReconBtn).Pressed = mode == CivFireSupportMode.Recon;
		((Control)VectorPanel).Visible = mode == CivFireSupportMode.Airstrike || mode == CivFireSupportMode.SmokeScreen;
		ClearStatus();
		RefreshCooldownLabel();
		RefreshStrikeButton();
		RefreshEtaLabel();
	}

	private void RefreshStrikeButton()
	{
		Button strikeBtn = StrikeBtn;
		strikeBtn.Text = _mode switch
		{
			CivFireSupportMode.Airstrike => Loc.GetString("civ-cmd-airstrike-strike-avia"), 
			CivFireSupportMode.SmokeScreen => Loc.GetString("civ-cmd-airstrike-strike-smoke"), 
			CivFireSupportMode.BallisticMissile => Loc.GetString("civ-cmd-airstrike-strike-missile"), 
			CivFireSupportMode.Recon => Loc.GetString("civ-cmd-airstrike-strike-recon"), 
			_ => Loc.GetString("civ-cmd-airstrike-strike-art"), 
		};
	}

	private void RefreshEtaLabel()
	{
		//IL_0051: Unknown result type (might be due to invalid IL or missing references)
		if (_mode == CivFireSupportMode.Airstrike)
		{
			ShowDefaultEta();
			ScheduleEta();
			return;
		}
		if (_mode == CivFireSupportMode.Recon)
		{
			EtaLabel.Text = Loc.GetString("civ-cmd-airstrike-eta-recon");
			return;
		}
		string text = ((_mode == CivFireSupportMode.BallisticMissile) ? "CivBallisticMissileDefault" : "CivArtilleryDefault");
		CivArtilleryConfigPrototype civArtilleryConfigPrototype = default(CivArtilleryConfigPrototype);
		if (_proto.TryIndex<CivArtilleryConfigPrototype>(new ProtoId<CivArtilleryConfigPrototype>(text), ref civArtilleryConfigPrototype))
		{
			EtaLabel.Text = Loc.GetString("civ-cmd-airstrike-eta-art", new(string, object)[2]
			{
				("delay", civArtilleryConfigPrototype.DelaySeconds.ToString("0.0")),
				("cost", civArtilleryConfigPrototype.BypassCost)
			});
		}
		else
		{
			EtaLabel.Text = string.Empty;
		}
	}

	private void ScheduleEta()
	{
		if (_system != null && _mode == CivFireSupportMode.Airstrike)
		{
			if (!float.TryParse(XInput.Text, out var result) || !float.TryParse(YInput.Text, out result))
			{
				ShowDefaultEta();
				return;
			}
			_nextEtaRequest = _timing.RealTime + TimeSpan.FromMilliseconds(250L);
			_etaPending = true;
		}
	}

	protected override void FrameUpdate(FrameEventArgs args)
	{
		//IL_0001: Unknown result type (might be due to invalid IL or missing references)
		((DefaultWindow)this).FrameUpdate(args);
		if (_etaPending && _system != null && _mode == CivFireSupportMode.Airstrike && !(_timing.RealTime < _nextEtaRequest))
		{
			if (!float.TryParse(XInput.Text, out var result) || !float.TryParse(YInput.Text, out var result2))
			{
				_etaPending = false;
				return;
			}
			_system.RequestEta(new Vector2(result, result2), _vector);
			_etaPending = false;
		}
	}

	private void OnEta(float seconds)
	{
		if (_mode == CivFireSupportMode.Airstrike)
		{
			if (seconds <= 0f)
			{
				EtaLabel.Text = string.Empty;
				return;
			}
			EtaLabel.Text = Loc.GetString("civ-cmd-airstrike-eta", new(string, object)[1] { ("seconds", seconds.ToString("0.0")) });
		}
	}

	private void ShowDefaultEta()
	{
		//IL_000b: Unknown result type (might be due to invalid IL or missing references)
		CivAirstrikeConfigPrototype civAirstrikeConfigPrototype = default(CivAirstrikeConfigPrototype);
		if (!_proto.TryIndex<CivAirstrikeConfigPrototype>(new ProtoId<CivAirstrikeConfigPrototype>("CivAirstrikeDefault"), ref civAirstrikeConfigPrototype))
		{
			EtaLabel.Text = string.Empty;
			return;
		}
		EtaLabel.Text = Loc.GetString("civ-cmd-airstrike-eta-default", new(string, object)[1] { ("seconds", civAirstrikeConfigPrototype.DelaySeconds.ToString("0.0")) });
	}

	private void OnStrike(ButtonEventArgs args)
	{
		if (_system == null)
		{
			return;
		}
		if (!float.TryParse(XInput.Text, out var result) || !float.TryParse(YInput.Text, out var result2))
		{
			ShowError(Loc.GetString("civ-cmd-airstrike-error-coords"));
			return;
		}
		Vector2 target = new Vector2(result, result2);
		if (_mode == CivFireSupportMode.Airstrike)
		{
			_system.RequestAirstrike(target, _vector);
		}
		else if (_mode == CivFireSupportMode.SmokeScreen)
		{
			_system.RequestSmokeSupport(target, _vector);
		}
		else if (_mode == CivFireSupportMode.BallisticMissile)
		{
			_system.RequestBallisticMissile(target);
		}
		else if (_mode == CivFireSupportMode.Recon)
		{
			_system.RequestReconDrone(target);
		}
		else
		{
			_system.RequestArtillery(target);
		}
	}

	private void OnMyPosition(ButtonEventArgs args)
	{
		Vector2? vector = _system?.GetMyPosition();
		if (vector.HasValue)
		{
			Vector2 valueOrDefault = vector.GetValueOrDefault();
			SetCoordinates(valueOrDefault);
			ClearStatus();
			ScheduleEta();
		}
	}

	private void OnTeleport(ButtonEventArgs args)
	{
		if (_system != null)
		{
			if (!float.TryParse(XInput.Text, out var result) || !float.TryParse(YInput.Text, out var result2))
			{
				ShowError(Loc.GetString("civ-cmd-airstrike-error-coords"));
			}
			else
			{
				_system.RequestTeleport(new Vector2(result, result2));
			}
		}
	}

	public void ShowError(string msg)
