	private void RefreshCooldownLabel()
	{
		float num = _mode switch
		{
			CivFireSupportMode.Airstrike => _airstrikeCooldown, 
			CivFireSupportMode.SmokeScreen => _smokeCooldown, 
			CivFireSupportMode.BallisticMissile => 0f, 
			CivFireSupportMode.Recon => 0f, 
			_ => _artilleryCooldown, 
		};
		string text = _mode switch
		{
			CivFireSupportMode.Airstrike => Loc.GetString("civ-cmd-airstrike-ready-avia"), 
			CivFireSupportMode.SmokeScreen => Loc.GetString("civ-cmd-airstrike-ready-smoke"), 
			CivFireSupportMode.BallisticMissile => Loc.GetString("civ-cmd-airstrike-ready-missile"), 
			CivFireSupportMode.Recon => Loc.GetString("civ-cmd-airstrike-ready-recon"), 
			_ => Loc.GetString("civ-cmd-airstrike-ready-art"), 
		};
		if (num <= 0f)
		{
			StatusLabel.Text = text;
			((Control)StatusLabel).StyleClasses.Clear();
			((Control)StatusLabel).AddStyleClass("LabelGood");
